import { useState } from "react";

// ─── EmailJS config – replace these 3 values ───────────────────────────
const EMAILJS_SERVICE_ID  = "service_ngfd67t";
const EMAILJS_TEMPLATE_ID = "template_53mf3p5";
const EMAILJS_PUBLIC_KEY  = "77kG6VV80oYTZcltG";
const OWNER_EMAIL         = "mohamad.ali10id@gmail.com";
// ────────────────────────────────────────────────────────────────────────
const FOOD_IMGS = {
  avocado:    "data:image/jpeg;base64,",
  cucumber:   "data:image/jpeg;base64,",
  california: "data:image/jpeg;base64,",
  spicycrab:  "data:image/jpeg;base64,",
};

const MENU = [
  {
    id: 1,
    name: "Avocado Roll",
    desc: "Creamy ripe avocado, seasoned sushi rice, toasted sesame, wrapped in nori",
    price: 11750,
    tag: "vegan",
    art: "avocado",
  },
  {
    id: 2,
    name: "Cucumber Roll",
    desc: "Cool crisp cucumber, light rice vinegar rice, wrapped in nori — clean and refreshing",
    price: 10500,
    tag: "vegan",
    art: "cucumber",
  },
  {
    id: 3,
    name: "Spicy Crab Roll",
    desc: "Real crab meat, spicy sriracha mayo, cucumber, avocado, tobiko on top",
    price: 17000,
    tag: "spicy",
    art: "spicycrab",
  },
  {
    id: 4,
    name: "California Roll",
    desc: "Imitation crab, fresh avocado, cucumber, sesame seeds — the all-time classic",
    price: 14500,
    tag: "classic",
    art: "california",
  },
];

const TAG_STYLE = {
  vegan:   { bg: "#E8F5E9", text: "#2E7D32", label: "🌿 Vegan" },
  spicy:   { bg: "#FFEBEE", text: "#C62828", label: "🌶 Spicy" },
  classic: { bg: "#FFF3E0", text: "#E65100", label: "⭐ Classic" },
};

const fmt = (n) => "IQD " + n.toLocaleString();

function Petal({ style }) {
  return (
    <div style={{
      position: "absolute",
      width: "9px", height: "11px",
      borderRadius: "50% 0 50% 0",
      background: "rgba(200,16,46,0.15)",
      animation: `fall ${style.duration}s linear ${style.delay}s infinite`,
      left: style.left, top: "-20px",
      transform: `rotate(${style.rot}deg)`,
      pointerEvents: "none",
    }} />
  );
}

function BlossomTree({ flip = false }) {
  return (
    <svg viewBox="0 0 120 200" width="110" height="200"
      style={{ transform: flip ? "scaleX(-1)" : "none", opacity: 0.8 }}>
      <path d="M60 200 Q58 160 55 130 Q52 100 60 70" stroke="#8B7355" strokeWidth="5" fill="none" strokeLinecap="round"/>
      <path d="M60 130 Q45 110 30 100" stroke="#8B7355" strokeWidth="3" fill="none" strokeLinecap="round"/>
      <path d="M60 115 Q75 95 90 88" stroke="#8B7355" strokeWidth="3" fill="none" strokeLinecap="round"/>
      <path d="M60 100 Q50 80 42 65" stroke="#8B7355" strokeWidth="2.5" fill="none" strokeLinecap="round"/>
      <path d="M60 95 Q70 75 80 62" stroke="#8B7355" strokeWidth="2.5" fill="none" strokeLinecap="round"/>
      <path d="M60 80 Q55 65 52 50" stroke="#8B7355" strokeWidth="2" fill="none" strokeLinecap="round"/>
      {[
        [30,96],[22,90],[38,88],[26,82],
        [90,84],[98,80],[84,76],[94,72],
        [42,62],[36,55],[50,58],[44,48],
        [80,58],[74,52],[84,50],[78,42],
        [52,46],[60,40],[56,32],[64,36],[50,28],
      ].map(([cx,cy],i) => (
        <g key={i}>
          {[0,72,144,216,288].map((angle,j) => (
            <ellipse key={j}
              cx={cx + 5*Math.cos(angle*Math.PI/180)}
              cy={cy + 5*Math.sin(angle*Math.PI/180)}
              rx="3.5" ry="2.5"
              transform={`rotate(${angle},${cx+5*Math.cos(angle*Math.PI/180)},${cy+5*Math.sin(angle*Math.PI/180)})`}
              fill="#F8BBD9" opacity="0.9"
            />
          ))}
          <circle cx={cx} cy={cy} r="2" fill="#FFCDD2"/>
        </g>
      ))}
    </svg>
  );
}

const PETALS = Array.from({ length: 12 }, () => ({
  left: `${Math.random() * 100}%`,
  duration: 6 + Math.random() * 6,
  delay: Math.random() * 8,
  rot: Math.random() * 360,
}));

export default function NamiSushi() {
  const [cart, setCart]       = useState({});
  const [screen, setScreen]   = useState("menu");
  const [name, setName]       = useState("");
  const [note, setNote]       = useState("");
  const [sending, setSending] = useState(false);

  const add    = (item) => setCart(p => ({ ...p, [item.id]: { ...item, qty: (p[item.id]?.qty||0)+1 } }));
  const remove = (id)   => setCart(p => {
    const u = { ...p };
    if (u[id].qty <= 1) delete u[id]; else u[id] = { ...u[id], qty: u[id].qty-1 };
    return u;
  });

  const cartItems  = Object.values(cart);
  const totalItems = cartItems.reduce((s,i) => s+i.qty, 0);
  const totalPrice = cartItems.reduce((s,i) => s+i.qty*i.price, 0);

  const sendEmail = async () => {
    setSending(true);
    const orderLines = cartItems.map(i => `${i.name} x${i.qty} — ${fmt(i.qty*i.price)}`).join("\n");
    try {
      await fetch("https://api.emailjs.com/api/v1.0/email/send", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          service_id: EMAILJS_SERVICE_ID,
          template_id: EMAILJS_TEMPLATE_ID,
          user_id: EMAILJS_PUBLIC_KEY,
          template_params: {
            to_email: OWNER_EMAIL,
            customer_name: name || "Guest",
            order_items: orderLines,
            order_total: fmt(totalPrice),
            customer_note: note || "None",
          },
        }),
      });
    } catch(e) {}
    setSending(false);
    setCart({}); setName(""); setNote("");
    setScreen("confirm");
  };

  const css = `
    @import url('https://fonts.googleapis.com/css2?family=Noto+Serif+JP:wght@400;700&family=Inter:wght@400;500;600;700&display=swap');
    @keyframes fall {
      0%   { transform: translateY(0) rotate(0deg) translateX(0); opacity:1; }
      50%  { transform: translateY(50vh) rotate(180deg) translateX(30px); opacity:0.6; }
      100% { transform: translateY(100vh) rotate(360deg) translateX(-10px); opacity:0; }
    }
    @keyframes fadeUp {
      from { opacity:0; transform:translateY(14px); }
      to   { opacity:1; transform:translateY(0); }
    }
    * { box-sizing:border-box; margin:0; padding:0; }
  `;

  const PetalLayer = () => (
    <div style={{ position:"fixed", inset:0, overflow:"hidden", pointerEvents:"none", zIndex:0 }}>
      {PETALS.map((p,i) => <Petal key={i} style={p}/>)}
    </div>
  );

  // ── CONFIRM ──────────────────────────────────────────────────────────────
  if (screen === "confirm") return (
    <>
      <style>{css}</style>
      <div style={{ minHeight:"100vh", background:"#FAFAF7", display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", fontFamily:"Inter,sans-serif", padding:"2rem", textAlign:"center", position:"relative" }}>
        <PetalLayer/>
        <div style={{ position:"relative", zIndex:1 }}>
          <div style={{ fontSize:"4rem", marginBottom:"1rem" }}>🌸</div>
          <h2 style={{ fontFamily:"'Noto Serif JP',serif", fontSize:"1.8rem", color:"#2C1810", marginBottom:"0.5rem" }}>Order received!</h2>
          <p style={{ color:"#8B7355", marginBottom:"0.3rem" }}>Thank you{name ? `, ${name}` : ""}!</p>
          <p style={{ color:"#8B7355", fontSize:"0.88rem", marginBottom:"2rem" }}>Pay in cash on delivery — we'll be in touch shortly 🙏</p>
          <button onClick={() => setScreen("menu")} style={{ background:"#C8102E", color:"white", border:"none", padding:"0.85rem 2.2rem", borderRadius:"2rem", fontWeight:700, fontSize:"1rem", cursor:"pointer" }}>
            Order again
          </button>
        </div>
      </div>
    </>
  );

  // ── CHECKOUT ─────────────────────────────────────────────────────────────
  if (screen === "checkout") return (
    <>
      <style>{css}</style>
      <div style={{ minHeight:"100vh", background:"#FAFAF7", fontFamily:"Inter,sans-serif", maxWidth:"480px", margin:"0 auto" }}>
        <div style={{ padding:"1.2rem 1.4rem", borderBottom:"1px solid #E8DDD0", display:"flex", alignItems:"center", gap:"0.8rem", background:"white", position:"sticky", top:0, zIndex:10 }}>
          <button onClick={() => setScreen("menu")} style={{ background:"none", border:"none", fontSize:"1.4rem", cursor:"pointer", color:"#2C1810" }}>←</button>
          <span style={{ fontFamily:"'Noto Serif JP',serif", fontSize:"1.2rem", fontWeight:700, color:"#2C1810" }}>Your Order</span>
        </div>

        <div style={{ padding:"1.2rem 1.4rem" }}>
          {cartItems.map(item => (
            <div key={item.id} style={{ display:"flex", alignItems:"center", gap:"0.9rem", marginBottom:"0.9rem", padding:"0.85rem", background:"white", borderRadius:"1rem", boxShadow:"0 1px 5px rgba(44,24,16,0.07)" }}>
              <div style={{ width:"60px", height:"60px", borderRadius:"0.6rem", flexShrink:0, overflow:"hidden", background:"#F5EDE8" }}>
                <svg viewBox="0 0 60 60" width="60" height="60">
                  <rect width="60" height="60" fill="#F5EDE8"/>
                  <circle cx="30" cy="30" r="14" fill="#1a1a1a"/>
                  <circle cx="30" cy="30" r="10" fill="#F5F0E8"/>
                  <circle cx="30" cy="30" r="6" fill={item.tag==="spicy"?"#E05A2B":item.tag==="classic"?"#E05A2B":"#5B8A3C"}/>
                </svg>
              </div>
              <div style={{ flex:1 }}>
                <div style={{ fontWeight:600, color:"#2C1810", fontSize:"0.95rem" }}>{item.name}</div>
                <div style={{ color:"#C8102E", fontWeight:700, fontSize:"0.9rem", marginTop:"0.2rem" }}>{fmt(item.price)} × {item.qty}</div>
              </div>
              <div style={{ display:"flex", alignItems:"center", gap:"0.5rem" }}>
                <button onClick={() => remove(item.id)} style={{ background:"#F5EDE8", border:"none", borderRadius:"50%", width:"30px", height:"30px", fontWeight:700, cursor:"pointer", color:"#2C1810", fontSize:"1rem" }}>−</button>
                <span style={{ fontWeight:700, color:"#2C1810", minWidth:"1rem", textAlign:"center" }}>{item.qty}</span>
                <button onClick={() => add(item)} style={{ background:"#F5EDE8", border:"none", borderRadius:"50%", width:"30px", height:"30px", fontWeight:700, cursor:"pointer", color:"#2C1810", fontSize:"1rem" }}>+</button>
              </div>
            </div>
          ))}

          <div style={{ borderTop:"1px dashed #E8DDD0", margin:"1rem 0", display:"flex", justifyContent:"space-between", paddingTop:"1rem" }}>
            <span style={{ fontFamily:"'Noto Serif JP',serif", fontWeight:700, color:"#2C1810", fontSize:"1.1rem" }}>Total</span>
            <span style={{ fontFamily:"'Noto Serif JP',serif", fontWeight:700, color:"#C8102E", fontSize:"1.2rem" }}>{fmt(totalPrice)}</span>
          </div>

          <p style={{ fontSize:"0.8rem", color:"#8B7355", marginBottom:"1.3rem", textAlign:"center", background:"#FFF8F0", padding:"0.6rem", borderRadius:"0.6rem" }}>
            💵 Payment collected in cash on delivery
          </p>

          <label style={{ display:"block", fontSize:"0.85rem", fontWeight:600, color:"#2C1810", marginBottom:"0.4rem" }}>Your name</label>
          <input value={name} onChange={e => setName(e.target.value)} placeholder="e.g. Ahmed"
            style={{ width:"100%", padding:"0.75rem 1rem", borderRadius:"0.75rem", border:"1.5px solid #E8DDD0", fontSize:"1rem", marginBottom:"1rem", fontFamily:"Inter,sans-serif", outline:"none", color:"#2C1810", background:"white" }} />

          <label style={{ display:"block", fontSize:"0.85rem", fontWeight:600, color:"#2C1810", marginBottom:"0.4rem" }}>
            Delivery note <span style={{ fontWeight:400, color:"#8B7355" }}>(optional)</span>
          </label>
          <textarea value={note} onChange={e => setNote(e.target.value)} placeholder="e.g. Leave at door, no wasabi..." rows={2}
            style={{ width:"100%", padding:"0.75rem 1rem", borderRadius:"0.75rem", border:"1.5px solid #E8DDD0", fontSize:"0.95rem", marginBottom:"1.5rem", fontFamily:"Inter,sans-serif", outline:"none", resize:"none", color:"#2C1810", background:"white" }} />

          <button onClick={sendEmail} disabled={sending || cartItems.length === 0}
            style={{ width:"100%", background: sending ? "#E8DDD0" : "#C8102E", color: sending ? "#8B7355" : "white", border:"none", padding:"1rem", borderRadius:"1rem", fontWeight:700, fontSize:"1rem", cursor: sending ? "not-allowed" : "pointer", fontFamily:"Inter,sans-serif", transition:"background 0.2s" }}>
            {sending ? "Placing order..." : `Confirm Order · ${fmt(totalPrice)}`}
          </button>
        </div>
      </div>
    </>
  );

  // ── MENU ─────────────────────────────────────────────────────────────────
  return (
    <>
      <style>{css}</style>
      <div style={{ minHeight:"100vh", background:"#FAFAF7", fontFamily:"Inter,sans-serif", maxWidth:"480px", margin:"0 auto", position:"relative" }}>
        <PetalLayer/>

        {/* hero */}
        <div style={{ position:"relative", background:"white", borderBottom:"1px solid #E8DDD0", overflow:"hidden", paddingBottom:"1.5rem" }}>
          <div style={{ position:"absolute", bottom:0, left:"-8px", zIndex:1, pointerEvents:"none" }}><BlossomTree/></div>
          <div style={{ position:"absolute", bottom:0, right:"-8px", zIndex:1, pointerEvents:"none" }}><BlossomTree flip/></div>
          <div style={{ textAlign:"center", padding:"2.5rem 1rem 0.8rem", position:"relative", zIndex:2 }}>
            <p style={{ fontSize:"0.68rem", letterSpacing:"0.25em", color:"#8B7355", textTransform:"uppercase", marginBottom:"0.4rem" }}>夏のメニュー · Summer Menu</p>
            <h1 style={{ fontFamily:"'Noto Serif JP',serif", fontSize:"2.5rem", fontWeight:700, color:"#2C1810", lineHeight:1.1, marginBottom:"0.3rem" }}>Nami Sushi</h1>
            <p style={{ color:"#8B7355", fontSize:"0.88rem" }}>Fresh rolls · Delivered to your door</p>
          </div>
        </div>

        {/* items */}
        <div style={{ padding:"1.2rem 1.2rem 9rem", position:"relative", zIndex:1 }}>
          <p style={{ fontSize:"0.72rem", letterSpacing:"0.15em", color:"#8B7355", textTransform:"uppercase", marginBottom:"1rem" }}>Today's Menu</p>

          {MENU.map((item, idx) => {
            const qty = cart[item.id]?.qty || 0;
            const tag = TAG_STYLE[item.tag];
            return (
              <div key={item.id} style={{ background:"white", borderRadius:"1.2rem", marginBottom:"1rem", overflow:"hidden", boxShadow:"0 2px 10px rgba(44,24,16,0.08)", animation:`fadeUp 0.35s ease ${idx*0.07}s both` }}>
                <div style={{ position:"relative" }}>
                  <img src={FOOD_IMGS[item.art]} alt={item.name} style={{ width:"100%", height:"175px", objectFit:"cover", display:"block" }}/>
                  {tag && (
                    <span style={{ position:"absolute", top:"10px", left:"10px", background:tag.bg, color:tag.text, fontSize:"0.68rem", fontWeight:700, padding:"0.2rem 0.6rem", borderRadius:"1rem", letterSpacing:"0.03em" }}>
                      {tag.label}
                    </span>
                  )}
                </div>
                <div style={{ padding:"1rem" }}>
                  <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:"0.3rem" }}>
                    <span style={{ fontFamily:"'Noto Serif JP',serif", fontWeight:700, color:"#2C1810", fontSize:"1.05rem" }}>{item.name}</span>
                    <span style={{ color:"#C8102E", fontWeight:700, fontSize:"1rem", flexShrink:0, marginLeft:"0.5rem" }}>{fmt(item.price)}</span>
                  </div>
                  <p style={{ color:"#8B7355", fontSize:"0.82rem", lineHeight:1.55, marginBottom:"0.9rem" }}>{item.desc}</p>
                  <div style={{ display:"flex", alignItems:"center", justifyContent:"flex-end", gap:"0.6rem" }}>
                    {qty > 0 && (
                      <>
                        <button onClick={() => remove(item.id)} style={{ background:"#F5EDE8", border:"none", borderRadius:"50%", width:"36px", height:"36px", fontWeight:700, fontSize:"1.1rem", cursor:"pointer", color:"#2C1810" }}>−</button>
                        <span style={{ fontWeight:700, color:"#2C1810", minWidth:"1.2rem", textAlign:"center", fontSize:"1rem" }}>{qty}</span>
                      </>
                    )}
                    <button onClick={() => add(item)} style={{ background:"#C8102E", border:"none", borderRadius:"50%", width:"36px", height:"36px", fontWeight:700, fontSize:"1.2rem", cursor:"pointer", color:"white" }}>+</button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        {/* sticky cart */}
        {totalItems > 0 && (
          <div style={{ position:"fixed", bottom:0, left:"50%", transform:"translateX(-50%)", width:"100%", maxWidth:"480px", padding:"1rem 1.2rem", background:"white", borderTop:"1px solid #E8DDD0", zIndex:50 }}>
            <button onClick={() => setScreen("checkout")}
              style={{ width:"100%", background:"#C8102E", color:"white", border:"none", padding:"1rem 1.2rem", borderRadius:"1rem", fontWeight:700, fontSize:"1rem", cursor:"pointer", display:"flex", justifyContent:"space-between", alignItems:"center", fontFamily:"Inter,sans-serif" }}>
              <span>View Order · {totalItems} item{totalItems>1?"s":""}</span>
              <span>{fmt(totalPrice)}</span>
            </button>
          </div>
        )}
      </div>
    </>
  );
}
